import jwt
import datetime
import os
import secrets
from typing import Optional


SECRET_KEY = os.environ.get("JWT_SECRET_KEY")
if not SECRET_KEY:
    raise RuntimeError(
        "JWT_SECRET_KEY environment variable must be set. "
        "Generate one with: python -c \"import secrets; print(secrets.token_hex(32))\""
    )

ALGORITHM = "HS256"
ACCESS_TOKEN_EXPIRE_MINUTES = 15
REFRESH_TOKEN_EXPIRE_MINUTES = 60 * 24 * 7  # 7 days
ISSUER = "auth-service"
AUDIENCE = "api-service"

ALLOWED_ROLES = frozenset({"admin", "user", "moderator", "viewer"})


def generate_access_token(user_id: str, role: str) -> str:
    """Generate a short-lived JWT access token for a user."""
    if not user_id or not isinstance(user_id, str):
        raise ValueError("user_id must be a non-empty string")
    if role not in ALLOWED_ROLES:
        raise ValueError(f"role must be one of: {', '.join(sorted(ALLOWED_ROLES))}")

    now = datetime.datetime.now(datetime.timezone.utc)
    payload = {
        "sub": user_id,
        "role": role,
        "type": "access",
        "iat": now,
        "exp": now + datetime.timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES),
        "nbf": now,
        "iss": ISSUER,
        "aud": AUDIENCE,
        "jti": secrets.token_hex(16),
    }
    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return token


def generate_refresh_token(user_id: str, role: str) -> str:
    """Generate a longer-lived JWT refresh token for obtaining new access tokens."""
    if not user_id or not isinstance(user_id, str):
        raise ValueError("user_id must be a non-empty string")
    if role not in ALLOWED_ROLES:
        raise ValueError(f"role must be one of: {', '.join(sorted(ALLOWED_ROLES))}")

    now = datetime.datetime.now(datetime.timezone.utc)
    payload = {
        "sub": user_id,
        "role": role,
        "type": "refresh",
        "iat": now,
        "exp": now + datetime.timedelta(minutes=REFRESH_TOKEN_EXPIRE_MINUTES),
        "nbf": now,
        "iss": ISSUER,
        "aud": AUDIENCE,
        "jti": secrets.token_hex(16),
    }
    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return token


def verify_token(token: str, expected_type: str = "access") -> dict:
    """
    Verify and decode a JWT token.

    Returns the decoded payload if valid.
    Raises jwt.exceptions on invalid/expired tokens.
    """
    if not token or not isinstance(token, str):
        raise ValueError("Token must be a non-empty string")
    if expected_type not in ("access", "refresh"):
        raise ValueError("expected_type must be 'access' or 'refresh'")

    try:
        payload = jwt.decode(
            token,
            SECRET_KEY,
            algorithms=[ALGORITHM],
            issuer=ISSUER,
            audience=AUDIENCE,
            options={
                "require": ["sub", "role", "type", "exp", "iat", "nbf", "iss", "aud", "jti"],
                "verify_exp": True,
                "verify_nbf": True,
                "verify_iss": True,
                "verify_aud": True,
            },
        )
    except jwt.ExpiredSignatureError:
        raise
    except jwt.InvalidTokenError:
        raise

    if payload.get("type") != expected_type:
        raise jwt.InvalidTokenError(
            f"Expected token type '{expected_type}', got '{payload.get('type')}'"
        )

    if payload.get("role") not in ALLOWED_ROLES:
        raise jwt.InvalidTokenError("Token contains invalid role")

    return payload


def generate_token_pair(user_id: str, role: str) -> dict:
    """Generate both access and refresh tokens for a user login."""
    access_token = generate_access_token(user_id, role)
    refresh_token = generate_refresh_token(user_id, role)
    return {
        "access_token": access_token,
        "refresh_token": refresh_token,
        "token_type": "Bearer",
        "expires_in": ACCESS_TOKEN_EXPIRE_MINUTES * 60,
    }


def refresh_access_token(refresh_token: str) -> dict:
    """Use a valid refresh token to generate a new access token."""
    payload = verify_token(refresh_token, expected_type="refresh")
    user_id = payload["sub"]
    role = payload["role"]
    new_access_token = generate_access_token(user_id, role)
    return {
        "access_token": new_access_token,
        "token_type": "Bearer",
        "expires_in": ACCESS_TOKEN_EXPIRE_MINUTES * 60,
    }


def get_user_from_token(token: str) -> Optional[dict]:
    """Extract user info from a verified access token. Returns None if invalid."""
    try:
        payload = verify_token(token, expected_type="access")
        return {
            "user_id": payload["sub"],
            "role": payload["role"],
        }
    except (jwt.InvalidTokenError, ValueError):
        return None


if __name__ == "__main__":
    print("Generating token pair for user 'user-123' with role 'admin'...")
    tokens = generate_token_pair("user-123", "admin")
    print(f"Access Token: {tokens['access_token'][:50]}...")
    print(f"Refresh Token: {tokens['refresh_token'][:50]}...")
    print(f"Expires in: {tokens['expires_in']} seconds")

    print("\nVerifying access token...")
    user_info = get_user_from_token(tokens["access_token"])
    print(f"User info: {user_info}")

    print("\nRefreshing access token...")
    new_tokens = refresh_access_token(tokens["refresh_token"])
    print(f"New Access Token: {new_tokens['access_token'][:50]}...")

    print("\nVerifying new access token...")
    user_info = get_user_from_token(new_tokens["access_token"])
    print(f"User info: {user_info}")